4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type QuoteStep = { type: "quote"; items: Item[] };
14	type Scenario = { steps: QuoteStep[] };
15	
16	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
17	  const { steps } = scenario as Scenario;
18	  const items = steps[0].items;
19	  const runeCount = items.filter((item) => item.type === "rune").length;
20	  const base =
21	    runeCount === 3
22	      ? 60
23	      : items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
24	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
25	  const premium = base + firstInsuranceSurcharge + PROCESSING_FEE;
26	  return { results: [{ premium }] };
27	}
